-- Legislacao Bloco 2 misto: Geraldo Alckmin / Camara Dados Abertos / projetos_lei
-- Promocao completa escopada: autoria principal em tipos legislativos canonicos
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos v2
--   https://dadosabertos.camara.leg.br/api/v2/deputados/65480
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes?idDeputadoAutor=65480&ordem=DESC&ordenarPor=id&itens=100&pagina=1..2
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = geraldo-alckmin-camara-completo-autoria-principal-tipos-legislativos-1987-1994-cutoff-20260509
--   coverage_scope = inventario_completo_camara_autoria_principal_tipos_legislativos_1987_1994_cutoff_20260509
--
-- Escopo: 104 proposicoes de autoria principal (ordemAssinatura=1) na Camara,
-- tipos legislativos canonicos PL, PLP, PDC e PRC, no mandato parlamentar
-- federal 1987-1994, com cutoff em 2026-05-09.
--
-- Esta migration escreve somente em projetos_lei.
-- Esta migration NAO escreve em legislacao_mandato_executivo; valida baseline
-- read-only de 55 rows LME que permanecem ampliado_parcial em superficie separada.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  lme_count int;
  conflicting_coverage int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'geraldo-alckmin';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'geraldo-alckmin: candidato ausente neste banco local/CI minimo; promocao Camara pulada';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl NOT IN (100, 109) THEN
    RAISE EXCEPTION 'Pre-condicao geraldo-alckmin: esperadas 100 rows antes do insert ou 109 rows idempotentes em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 55 THEN
    RAISE EXCEPTION 'Pre-condicao geraldo-alckmin: baseline LME parcial esperado 55, encontrado %', lme_count;
  END IF;

  SELECT count(*) INTO conflicting_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('234878', '234499', '233455', '233320', '233258', '233212', '233191', '229775', '229657', '229544', '229257', '229253', '229249', '229039', '229035', '228484', '228480', '228476', '227650', '226966', '226867', '226677', '225664', '225476', '223982', '223823', '222881', '222839', '222023', '221106', '217409', '217009', '216874', '216799', '216342', '215935', '215748', '215087', '214842', '214537', '213160', '213151', '212319', '208809', '207273', '206563', '206535', '204443', '202180', '201963', '200252', '197958', '197785', '197562', '196927', '196281', '195659', '195577', '192536', '192523', '191437', '191267', '190055', '189647', '189573', '188115', '187656', '187563', '185081', '184824', '184809', '184360', '184345', '184331', '183976', '182846', '182248', '180314', '180298', '180281', '180266', '180251', '179914', '179671', '178962', '178286', '171522', '170714', '170698', '167224', '25761', '21373', '21364', '21230', '21221', '21211', '20898', '19015', '16774', '16512', '16509', '15430', '15361', '14975')
    AND coverage_id IS NOT NULL
    AND coverage_id NOT IN ('geraldo-alckmin-camara-autoria-principal-ampliado-parcial-lote-a-20260506', 'geraldo-alckmin-camara-completo-autoria-principal-tipos-legislativos-1987-1994-cutoff-20260509');
  IF conflicting_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao geraldo-alckmin: % rows alvo tem coverage_id divergente', conflicting_coverage;
  END IF;
END $$;

