WITH cand AS (
  SELECT id AS candidato_id
  FROM candidatos
  WHERE slug = 'geraldo-alckmin'
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  url_inteiro_teor,
  fonte,
  proposicao_id_api,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  cand.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.url_inteiro_teor,
  'Camara',
  seed.proposicao_id_api,
  'geraldo-alckmin-camara-completo-autoria-principal-tipos-legislativos-1987-1994-cutoff-20260509',
  'inventario_completo_camara_autoria_principal_tipos_legislativos_1987_1994_cutoff_20260509',
  seed.metadata_patch
FROM cand
CROSS JOIN _geraldo_alckmin_camara_completo_20260509 seed
WHERE NOT EXISTS (
  SELECT 1
  FROM projetos_lei pl
  WHERE pl.candidato_id = cand.candidato_id
    AND pl.proposicao_id_api = seed.proposicao_id_api
);

WITH cand AS (
  SELECT id AS candidato_id
  FROM candidatos
  WHERE slug = 'geraldo-alckmin'
)
UPDATE projetos_lei pl
SET
  coverage_id = 'geraldo-alckmin-camara-completo-autoria-principal-tipos-legislativos-1987-1994-cutoff-20260509',
  coverage_scope = 'inventario_completo_camara_autoria_principal_tipos_legislativos_1987_1994_cutoff_20260509',
  metadata = COALESCE(pl.metadata, '{}'::jsonb) || seed.metadata_patch
FROM cand
JOIN _geraldo_alckmin_camara_completo_20260509 seed ON TRUE
WHERE pl.candidato_id = cand.candidato_id
  AND pl.proposicao_id_api = seed.proposicao_id_api
  AND (pl.coverage_id IS NULL OR pl.coverage_id IN ('geraldo-alckmin-camara-autoria-principal-ampliado-parcial-lote-a-20260506', 'geraldo-alckmin-camara-completo-autoria-principal-tipos-legislativos-1987-1994-cutoff-20260509'));

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  complete_count int;
  old_partial_count int;
  null_count int;
  lme_count int;
  other_slugs_with_target int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'geraldo-alckmin';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'geraldo-alckmin: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 109 THEN
    RAISE EXCEPTION 'Pos-apply geraldo-alckmin: esperado total projetos_lei=109, encontrado %', total_pl;
  END IF;

  SELECT count(*) INTO complete_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'geraldo-alckmin-camara-completo-autoria-principal-tipos-legislativos-1987-1994-cutoff-20260509'
    AND coverage_scope = 'inventario_completo_camara_autoria_principal_tipos_legislativos_1987_1994_cutoff_20260509';
  IF complete_count <> 104 THEN
    RAISE EXCEPTION 'Pos-apply geraldo-alckmin: esperadas 104 rows com coverage completo Camara, encontradas %', complete_count;
  END IF;

  SELECT count(*) INTO old_partial_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'geraldo-alckmin-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF old_partial_count <> 3 THEN
    RAISE EXCEPTION 'Pos-apply geraldo-alckmin: esperadas 3 rows procedimentais ainda no coverage parcial antigo, encontradas %', old_partial_count;
  END IF;

  SELECT count(*) INTO null_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id IS NULL;
  IF null_count <> 2 THEN
    RAISE EXCEPTION 'Pos-apply geraldo-alckmin: esperadas 2 rows coassinadas fora do recorte completo, encontradas %', null_count;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 55 THEN
    RAISE EXCEPTION 'Pos-apply geraldo-alckmin: LME deveria permanecer 55, encontrado %', lme_count;
  END IF;

  SELECT count(*) INTO other_slugs_with_target
  FROM projetos_lei
  WHERE candidato_id <> cand_id
    AND coverage_id = 'geraldo-alckmin-camara-completo-autoria-principal-tipos-legislativos-1987-1994-cutoff-20260509';
  IF other_slugs_with_target <> 0 THEN
    RAISE EXCEPTION 'Pos-apply geraldo-alckmin: % rows de outros slugs com coverage_id alvo', other_slugs_with_target;
  END IF;

  RAISE NOTICE 'Pos-apply geraldo-alckmin Camara completo scoped: projetos_lei=% complete=% old_partial=% null=% lme=%',
    total_pl, complete_count, old_partial_count, null_count, lme_count;
END $$;
